/*
 * Per-syllable tone targets.
 *
 * Resolves a target shape (Legendre coefficients c0..c3 over normalized
 * time [-1, +1]) for a (syllable, tone) pair, with a two-tier strategy:
 *
 *   1. Tone Perfect-derived data, if present in `targets.json`. This is
 *      averaged across the corpus's six native speakers, normalized
 *      to semitones-re-speaker-mean. Generated by
 *      `scripts/build-targets.mjs` from the Tone Perfect distribution.
 *
 *   2. A canonical fallback approximating Mandarin citation tones from
 *      the phonetics literature (Xu 1997, Prom-on et al. 2009 qTA).
 *      Used for any syllable not in the corpus or before targets.json
 *      has been generated.
 *
 * Coefficients are interpreted by both `viz.js` (target band) and
 * eventually a future per-syllable classifier (currently the classifier
 * is rule-based and uses canonical thresholds — see classifier.js).
 *
 * For each tone, mean of contour over [0, 1] equals c0 (since the
 * non-c0 Legendre terms integrate to zero on [-1, +1]).
 */

const FALLBACK = {
  1: { coefs: [5.0,  0.0,  0.0,  0.0]  },  // high level
  2: { coefs: [1.0,  4.0,  0.5,  0.0]  },  // rising, slight late acceleration
  3: { coefs: [-3.0, -1.0, 3.5,  0.3]  },  // low dip, asymmetric (later minimum)
  4: { coefs: [1.0, -5.0, -0.3,  0.0]  }   // high fall, brief plateau before drop
};

let LOADED = null;

/**
 * Fetch and cache `targets.json`. Returns the parsed corpus map (or
 * an empty object if missing or unparsable). Safe to call repeatedly.
 */
export async function loadTargets (url = './targets.json') {
  if (LOADED !== null) return LOADED;
  try {
    const res = await fetch(url);
    if (!res.ok) { LOADED = {}; return LOADED; }
    LOADED = await res.json();
  } catch (_e) {
    LOADED = {};
  }
  return LOADED;
}

/**
 * Get all four tone targets for a given base syllable.
 * Returns: { 1: {coefs, source, n?}, 2: {...}, 3: {...}, 4: {...} }
 *
 * `source` is 'tone-perfect' or 'canonical-fallback' so callers can
 * surface this for debugging or tuning.
 */
export function getSyllableTargets (syllable) {
  const tp = LOADED && LOADED.syllables && LOADED.syllables[syllable];
  const out = {};
  for (let t = 1; t <= 4; t++) {
    const entry = tp && tp[t];
    if (entry && Array.isArray(entry.coefs) && entry.coefs.length >= 4) {
      out[t] = {
        coefs: entry.coefs.slice(0, 4),
        source: 'tone-perfect',
        n: entry.n || null,
        sd: Array.isArray(entry.sd) ? entry.sd.slice(0, 4) : null
      };
    } else {
      out[t] = { coefs: FALLBACK[t].coefs.slice(), source: 'canonical-fallback' };
    }
  }
  return out;
}

/** Convenience: just the coefs for one (syllable, tone) pair. */
export function getTargetCoefs (syllable, tone) {
  return getSyllableTargets(syllable)[tone].coefs;
}
